{
  "name": "Coin Étudiant Eats",
  "description": "The ultimate food ordering app for students. Fresh, fast, and friendly."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface MenuItem {
  id: string;
  name: string;
  price: number;
  category: 'sandwich' | 'salad';
  description: string;
  imageUrl: string;
}

export interface CartItem extends MenuItem {
  quantity: number;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  isError?: boolean;
}

import { MenuItem } from './types';

export const MENU_ITEMS: MenuItem[] = [
  {
    id: '1',
    name: 'Salade au poulet',
    price: 10.99,
    category: 'salad',
    description: 'Poulet grillé tendre sur un lit de laitue fraîche, croûtons, parmesan et vinaigrette César.',
    imageUrl: 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&w=800&q=80'
  },
  {
    id: '2',
    name: 'Sandwich au poulet grillé',
    price: 7.99,
    category: 'sandwich',
    description: 'Poitrine de poulet marinée, tomates fraîches, laitue croustillante et mayonnaise maison.',
    imageUrl: 'https://images.unsplash.com/photo-1528735602780-2552fd46c7af?auto=format&fit=crop&w=800&q=80'
  },
  {
    id: '3',
    name: 'Salade verte',
    price: 9.99,
    category: 'salad',
    description: 'Mélange printanier, concombres, tomates cerises, avocat et vinaigrette balsamique légère.',
    imageUrl: 'https://images.unsplash.com/photo-1512621776951-a57141f2eefd?auto=format&fit=crop&w=800&q=80'
  },
  {
    id: '4',
    name: 'Sandwich au boeuf',
    price: 8.99,
    category: 'sandwich',
    description: 'Rôti de bœuf tranché finement, fromage suisse, oignons caramélisés et moutarde de Dijon.',
    imageUrl: 'https://images.unsplash.com/photo-1619860860774-1e2e1737e342?auto=format&fit=crop&w=800&q=80'
  },
  {
    id: '5',
    name: 'Sandwich au poulet croustillant',
    price: 8.99,
    category: 'sandwich',
    description: 'Filet de poulet pané, laitue, cornichons et sauce épicée signature dans un pain brioché.',
    imageUrl: 'https://images.unsplash.com/photo-1626082927389-6cd097cdc6ec?auto=format&fit=crop&w=800&q=80'
  }
];

import React, { useState, useRef, useEffect } from 'react';
import { ShoppingCart, X, MessageSquare, Send, Plus, Minus, Trash2, ChefHat, Loader2 } from 'lucide-react';
import { GoogleGenAI, Chat } from "@google/genai";
import { MENU_ITEMS } from './constants';
import { CartItem, MenuItem, ChatMessage } from './types';

// Initialize Gemini API
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

function App() {
  // State
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: 'welcome', role: 'model', text: 'Salut ! Je suis ton Assistant Gourmand. Tu as un petit creux ? Demande-moi ce qui est bon aujourd\'hui !' }
  ]);
  const [inputMessage, setInputMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  // Refs
  const chatEndRef = useRef<HTMLDivElement>(null);
  const chatSessionRef = useRef<Chat | null>(null);

  // Initialize Chat Session
  useEffect(() => {
    const menuContext = MENU_ITEMS.map(item => 
      `- ${item.name} (${item.price}$): ${item.description}`
    ).join('\n');

    const systemInstruction = `Tu es un assistant amical et énergique pour "Coin Étudiant Eats".
    Ta mission est d'aider les étudiants à choisir leur repas.
    Voici le menu actuel :
    ${menuContext}

    Règles :
    1. Réponds toujours en français.
    2. Sois concis et utilise un ton jeune et sympathique.
    3. Si on te demande quelque chose de sain, suggère les salades.
    4. Si on te demande quelque chose de consistant ou pas cher, suggère les sandwichs.
    5. N'invente pas de plats qui ne sont pas dans le menu.
    `;

    chatSessionRef.current = ai.chats.create({
      model: 'gemini-2.5-flash',
      config: {
        systemInstruction,
        temperature: 0.7,
      }
    });
  }, []);

  // Scroll to bottom of chat
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isChatOpen]);

  // Cart Functions
  const addToCart = (item: MenuItem) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { ...item, quantity: 1 }];
    });
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = item.quantity + delta;
        return newQty > 0 ? { ...item, quantity: newQty } : item;
      }
      return item;
    }));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(i => i.id !== id));
  };

  const total = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalItems = cart.reduce((sum, item) => sum + item.quantity, 0);

  // Chat Functions
  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputMessage.trim() || !chatSessionRef.current) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: inputMessage
    };

    setMessages(prev => [...prev, userMsg]);
    setInputMessage('');
    setIsLoading(true);

    try {
      const result = await chatSessionRef.current.sendMessage({ message: userMsg.text });
      const modelMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: result.text
      };
      setMessages(prev => [...prev, modelMsg]);
    } catch (error) {
      console.error("Chat error:", error);
      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Oups, j'ai eu un petit problème de connexion. Réessaie !",
        isError: true
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-sans">
      {/* Navbar */}
      <nav className="bg-indigo-600 text-white shadow-md sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex items-center gap-2">
              <div className="bg-white p-1.5 rounded-full">
                <ChefHat className="h-6 w-6 text-indigo-600" />
              </div>
              <span className="font-bold text-xl tracking-tight">Coin Étudiant Eats</span>
            </div>
            <button 
              onClick={() => setIsCartOpen(true)}
              className="relative p-2 hover:bg-indigo-700 rounded-full transition-colors"
            >
              <ShoppingCart className="h-6 w-6" />
              {totalItems > 0 && (
                <span className="absolute -top-1 -right-1 bg-yellow-400 text-indigo-900 text-xs font-bold w-5 h-5 flex items-center justify-center rounded-full border-2 border-indigo-600">
                  {totalItems}
                </span>
              )}
            </button>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <div className="bg-indigo-800 text-white py-12 px-4 sm:px-6 lg:px-8">
        <div className="max-w-7xl mx-auto text-center">
          <h1 className="text-3xl sm:text-4xl font-extrabold mb-4">
            Faim pendant tes études ?
          </h1>
          <p className="text-indigo-200 text-lg max-w-2xl mx-auto">
            Commande tes plats préférés directement depuis le Coin Étudiant. Rapide, frais et abordable.
          </p>
        </div>
      </div>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 flex-grow w-full">
        <h2 className="text-2xl font-bold text-gray-800 mb-6 border-b pb-2 border-gray-200">
          Notre Menu
        </h2>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {MENU_ITEMS.map((item) => (
            <div key={item.id} className="bg-white rounded-xl shadow-sm hover:shadow-md transition-shadow duration-300 overflow-hidden border border-gray-100 flex flex-col">
              <div className="h-48 overflow-hidden relative">
                 <img 
                   src={item.imageUrl} 
                   alt={item.name}
                   className="w-full h-full object-cover transform hover:scale-105 transition-transform duration-500"
                 />
                 <div className="absolute top-2 right-2 bg-white/90 backdrop-blur-sm px-2 py-1 rounded-md text-sm font-bold text-indigo-700 shadow-sm">
                   {item.price}$
                 </div>
              </div>
              <div className="p-5 flex flex-col flex-grow">
                <div className="flex justify-between items-start mb-2">
                  <h3 className="text-lg font-bold text-gray-900 leading-tight">{item.name}</h3>
                </div>
                <p className="text-gray-500 text-sm mb-4 flex-grow">{item.description}</p>
                <button
                  onClick={() => addToCart(item)}
                  className="w-full bg-indigo-50 hover:bg-indigo-100 text-indigo-700 font-semibold py-2.5 px-4 rounded-lg flex items-center justify-center gap-2 transition-colors duration-200"
                >
                  <Plus className="h-4 w-4" />
                  Ajouter au panier
                </button>
              </div>
            </div>
          ))}
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-white border-t border-gray-200 mt-12 py-8">
        <div className="max-w-7xl mx-auto px-4 text-center text-gray-400 text-sm">
          &copy; {new Date().getFullYear()} Coin Étudiant Eats. Fait avec passion pour les étudiants.
        </div>
      </footer>

      {/* Cart Sidebar */}
      {isCartOpen && (
        <div className="fixed inset-0 z-50 overflow-hidden">
          <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setIsCartOpen(false)} />
          <div className="absolute inset-y-0 right-0 max-w-full flex">
            <div className="w-screen max-w-md bg-white shadow-2xl flex flex-col h-full transform transition-transform duration-300">
              <div className="flex items-center justify-between p-4 border-b">
                <h2 className="text-lg font-bold text-gray-900 flex items-center gap-2">
                  <ShoppingCart className="h-5 w-5 text-indigo-600" />
                  Ton Panier
                </h2>
                <button onClick={() => setIsCartOpen(false)} className="text-gray-400 hover:text-gray-500">
                  <X className="h-6 w-6" />
                </button>
              </div>

              <div className="flex-1 overflow-y-auto p-4 space-y-4">
                {cart.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center text-gray-400">
                    <ShoppingCart className="h-16 w-16 mb-4 opacity-20" />
                    <p>Ton panier est vide.</p>
                    <button 
                      onClick={() => setIsCartOpen(false)}
                      className="mt-4 text-indigo-600 font-medium hover:underline"
                    >
                      Retourner au menu
                    </button>
                  </div>
                ) : (
                  cart.map(item => (
                    <div key={item.id} className="flex gap-4 p-3 bg-gray-50 rounded-lg border border-gray-100">
                      <img src={item.imageUrl} alt={item.name} className="w-16 h-16 rounded-md object-cover" />
                      <div className="flex-1">
                        <h3 className="font-semibold text-gray-900 text-sm">{item.name}</h3>
                        <p className="text-indigo-600 font-bold text-sm">{item.price}$</p>
                        <div className="flex items-center gap-3 mt-2">
                          <button 
                            onClick={() => updateQuantity(item.id, -1)}
                            className="p-1 rounded-full bg-white border border-gray-200 hover:bg-gray-100 text-gray-600"
                          >
                            <Minus className="h-3 w-3" />
                          </button>
                          <span className="text-sm font-medium w-4 text-center">{item.quantity}</span>
                          <button 
                            onClick={() => updateQuantity(item.id, 1)}
                            className="p-1 rounded-full bg-white border border-gray-200 hover:bg-gray-100 text-gray-600"
                          >
                            <Plus className="h-3 w-3" />
                          </button>
                        </div>
                      </div>
                      <button 
                        onClick={() => removeFromCart(item.id)}
                        className="text-gray-400 hover:text-red-500 self-start"
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </div>
                  ))
                )}
              </div>

              {cart.length > 0 && (
                <div className="border-t p-4 bg-gray-50">
                  <div className="flex justify-between items-center mb-4">
                    <span className="text-gray-600">Total</span>
                    <span className="text-2xl font-bold text-gray-900">{total.toFixed(2)}$</span>
                  </div>
                  <button 
                    onClick={() => alert('Commande envoyée ! Merci.')}
                    className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 active:scale-[0.98] transition-all shadow-lg shadow-indigo-200"
                  >
                    Commander maintenant
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* AI Chat Widget */}
      <div className="fixed bottom-6 right-6 z-40 flex flex-col items-end pointer-events-none">
        {isChatOpen && (
          <div className="pointer-events-auto mb-4 w-80 sm:w-96 bg-white rounded-2xl shadow-2xl border border-gray-100 overflow-hidden flex flex-col max-h-[500px] animate-in slide-in-from-bottom-5 duration-200">
            <div className="bg-indigo-600 p-4 flex justify-between items-center text-white">
              <div className="flex items-center gap-2">
                <MessageSquare className="h-5 w-5" />
                <span className="font-bold">Assistant Gourmand</span>
              </div>
              <button onClick={() => setIsChatOpen(false)} className="hover:bg-indigo-700 p-1 rounded-full">
                <X className="h-4 w-4" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50 h-80">
              {messages.map((msg) => (
                <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[80%] p-3 rounded-2xl text-sm ${
                    msg.role === 'user' 
                      ? 'bg-indigo-600 text-white rounded-br-sm' 
                      : 'bg-white border border-gray-200 text-gray-800 rounded-bl-sm shadow-sm'
                  }`}>
                    {msg.text}
                  </div>
                </div>
              ))}
              {isLoading && (
                <div className="flex justify-start">
                  <div className="bg-white border border-gray-200 p-3 rounded-2xl rounded-bl-sm shadow-sm flex items-center gap-2">
                    <Loader2 className="h-4 w-4 animate-spin text-indigo-600" />
                    <span className="text-xs text-gray-500">En train de réfléchir...</span>
                  </div>
                </div>
              )}
              <div ref={chatEndRef} />
            </div>

            <form onSubmit={handleSendMessage} className="p-3 bg-white border-t flex gap-2">
              <input
                type="text"
                value={inputMessage}
                onChange={(e) => setInputMessage(e.target.value)}
                placeholder="Ex: J'ai envie de quelque chose de léger..."
                className="flex-1 bg-gray-100 text-gray-900 border-0 rounded-full px-4 py-2 focus:ring-2 focus:ring-indigo-500 text-sm"
              />
              <button 
                type="submit" 
                disabled={isLoading || !inputMessage.trim()}
                className="bg-indigo-600 text-white p-2 rounded-full hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                <Send className="h-4 w-4" />
              </button>
            </form>
          </div>
        )}

        <button
          onClick={() => setIsChatOpen(!isChatOpen)}
          className="pointer-events-auto bg-indigo-600 hover:bg-indigo-700 text-white p-4 rounded-full shadow-xl hover:shadow-2xl transition-all duration-200 transform hover:scale-105 active:scale-95 flex items-center justify-center group"
        >
          {isChatOpen ? <X className="h-6 w-6" /> : <MessageSquare className="h-6 w-6" />}
          {!isChatOpen && (
            <span className="absolute right-full mr-4 bg-white text-gray-800 px-3 py-1.5 rounded-lg text-sm font-medium shadow-md whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
              Besoin d'aide ?
            </span>
          )}
        </button>
      </div>
    </div>
  );
}

export default App;

