import React, { useState, useRef, useEffect } from 'react';
import { ShoppingCart, X, MessageSquare, Send, Plus, Minus, Trash2, Leaf, Loader2 } from 'lucide-react';
import { GoogleGenAI, Chat } from "@google/genai";
import { MENU_ITEMS } from './constants';
import { CartItem, MenuItem, ChatMessage } from './types';

// Initialize Gemini API
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

function App() {
  // State
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: 'welcome', role: 'model', text: 'Salut ! Bienvenue au Coin Étudiant. Besoin d\'aide pour choisir un repas santé ?' }
  ]);
  const [inputMessage, setInputMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  // Refs
  const chatEndRef = useRef<HTMLDivElement>(null);
  const chatSessionRef = useRef<Chat | null>(null);

  // Initialize Chat Session
  useEffect(() => {
    const menuContext = MENU_ITEMS.map(item => 
      `- ${item.name} (${item.price}$): ${item.description}`
    ).join('\n');

    const systemInstruction = `Tu es un assistant amical pour "Le Coin Étudiant".
    Le style du restaurant est "Natural Food", vert et santé.
    Ta mission est d'aider les étudiants à choisir leur repas.
    Voici le menu actuel :
    ${menuContext}

    Règles :
    1. Réponds toujours en français.
    2. Sois concis et utilise un ton jeune, dynamique et écologique.
    3. Mets l'accent sur la fraîcheur et les ingrédients naturels.
    4. N'invente pas de plats qui ne sont pas dans le menu.
    `;

    chatSessionRef.current = ai.chats.create({
      model: 'gemini-2.5-flash',
      config: {
        systemInstruction,
        temperature: 0.7,
      }
    });
  }, []);

  // Scroll to bottom of chat
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isChatOpen]);

  // Cart Functions
  const addToCart = (item: MenuItem) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { ...item, quantity: 1 }];
    });
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = item.quantity + delta;
        return newQty > 0 ? { ...item, quantity: newQty } : item;
      }
      return item;
    }));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(i => i.id !== id));
  };

  const total = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalItems = cart.reduce((sum, item) => sum + item.quantity, 0);

  // Chat Functions
  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputMessage.trim() || !chatSessionRef.current) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: inputMessage
    };

    setMessages(prev => [...prev, userMsg]);
    setInputMessage('');
    setIsLoading(true);

    try {
      const result = await chatSessionRef.current.sendMessage({ message: userMsg.text });
      const modelMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: result.text
      };
      setMessages(prev => [...prev, modelMsg]);
    } catch (error) {
      console.error("Chat error:", error);
      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Oups, j'ai eu un petit problème de connexion. Réessaie !",
        isError: true
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-green-50 flex flex-col font-sans">
      {/* Navbar */}
      <nav className="bg-green-700 text-white shadow-lg sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-20 items-center">
            <div className="flex items-center gap-3">
              <div className="bg-white p-2 rounded-full shadow-md">
                {/* Replaced ChefHat with Leaf to match the logo description */}
                <Leaf className="h-8 w-8 text-green-700 fill-current" />
              </div>
              <div className="flex flex-col">
                <span className="font-bold text-xl tracking-tight leading-none">Le Coin Étudiant</span>
                <span className="text-xs text-green-200 font-medium">Mange vert, reste fier</span>
              </div>
