                <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] p-3.5 rounded-2xl text-sm leading-relaxed ${
                    msg.role === 'user' 
                      ? 'bg-green-600 text-white rounded-br-sm shadow-md' 
                      : 'bg-white border border-gray-200 text-gray-800 rounded-bl-sm shadow-sm'
                  }`}>
                    {msg.text}
                  </div>
                </div>
              ))}
              {isLoading && (
                <div className="flex justify-start">
                  <div className="bg-white border border-gray-200 p-3 rounded-2xl rounded-bl-sm shadow-sm flex items-center gap-2">
                    <Loader2 className="h-4 w-4 animate-spin text-green-600" />
                    <span className="text-xs text-gray-500 font-medium">Réflexion en cours...</span>
                  </div>
                </div>
              )}
              <div ref={chatEndRef} />
            </div>

            <form onSubmit={handleSendMessage} className="p-3 bg-white border-t border-gray-100 flex gap-2">
              <input
                type="text"
                value={inputMessage}
                onChange={(e) => setInputMessage(e.target.value)}
                placeholder="Ex: Quel est le meilleur abonnement ?"
                className="flex-1 bg-gray-100 text-gray-900 border-0 rounded-full px-4 py-2 focus:ring-2 focus:ring-green-500 text-sm transition-shadow"
              />
              <button 
                type="submit" 
                disabled={isLoading || !inputMessage.trim()}
                className="bg-green-600 text-white p-2.5 rounded-full hover:bg-green-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors shadow-md"
              >
                <Send className="h-4 w-4" />
              </button>
            </form>
          </div>
        )}

        <button
          onClick={() => setIsChatOpen(!isChatOpen)}
          className="pointer-events-auto bg-green-600 hover:bg-green-700 text-white p-4 rounded-full shadow-xl hover:shadow-2xl hover:shadow-green-900/20 transition-all duration-200 transform hover:scale-110 active:scale-95 flex items-center justify-center group"
        >
          {isChatOpen ? <X className="h-6 w-6" /> : <MessageSquare className="h-6 w-6" />}
          {!isChatOpen && (
            <span className="absolute right-full mr-4 bg-white text-gray-800 px-4 py-2 rounded-lg text-sm font-bold shadow-md whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none border border-green-100 text-green-800">
              Besoin d'aide ?
            </span>
          )}
        </button>
      </div>
    </div>
  );
}

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { ShoppingCart, X, MessageSquare, Send, Plus, Minus, Trash2, Leaf, Loader2, Calendar, CheckCircle2, ArrowRight, ArrowLeft, MapPin, CreditCard, User, Mail, Phone, Edit3 } from 'lucide-react';
import { GoogleGenAI, Chat } from "@google/genai";
import { MENU_ITEMS } from './constants';
import { CartItem, MenuItem, ChatMessage } from './types';

// Initialize Gemini API
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

function App() {
  // Navigation State
  const [currentView, setCurrentView] = useState<'menu' | 'subscription' | 'checkout'>('menu');

  // Shop State
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);

  // Customization State
  const [isCustomizing, setIsCustomizing] = useState<MenuItem | null>(null);
  const [customizationOptions, setCustomizationOptions] = useState<string[]>([]);
  const [customizationNotes, setCustomizationNotes] = useState('');

  // Checkout Form State
  const [checkoutForm, setCheckoutForm] = useState({
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    address: '',
    postalCode: '',
    paymentMethod: 'card', // 'card' or 'cash'
    savePayment: false,
    cardName: '',
    cardNumber: '',
    cardExpiry: '',
    cardCVC: ''
  });

  // Chat State
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: 'welcome', role: 'model', text: 'Salut ! Bienvenue au Coin Étudiant. Besoin d\'aide pour choisir un repas ou un abonnement ?' }
  ]);
  const [inputMessage, setInputMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  // Subscription State
  const [selectedPlan, setSelectedPlan] = useState<'weekly' | 'daily' | null>(null);
  const [subSalad, setSubSalad] = useState<string>('');
  const [subSandwich, setSubSandwich] = useState<string>('');

  // Refs
  const chatEndRef = useRef<HTMLDivElement>(null);
  const chatSessionRef = useRef<Chat | null>(null);

  // Derived Data
  const salads = MENU_ITEMS.filter(item => item.category === 'salad');
  const sandwiches = MENU_ITEMS.filter(item => item.category === 'sandwich');

  // Initialize Chat Session
  useEffect(() => {
    const menuContext = MENU_ITEMS.map(item => 
      `- ${item.name} (${item.price}$): ${item.description}`
    ).join('\n');

    const systemInstruction = `Tu es un assistant amical pour "Le Coin Étudiant".
    Le style du restaurant est "Natural Food", vert et santé.
    Ta mission est d'aider les étudiants à choisir leur repas ou leur abonnement.

    MENU :
    ${menuContext}

    ABONNEMENTS DISPONIBLES :
    1. Abonnement Hebdomadaire (15.99$ / semaine) : Reçois 1 repas (1 Salade + 1 Sandwich) chaque semaine.
    2. Abonnement Quotidien (20.99$ / jour) : Reçois 1 repas (1 Salade + 1 Sandwich) chaque jour.

    Règles :
    1. Réponds toujours en français.
    2. Sois concis, jeune et dynamique.
    3. Si l'utilisateur parle d'économiser ou de régularité, propose les abonnements.
    4. Mets l'accent sur la fraîcheur.
    `;

    chatSessionRef.current = ai.chats.create({
      model: 'gemini-2.5-flash',
      config: {
        systemInstruction,
        temperature: 0.7,
      }
    });
  }, []);

  // Scroll to bottom of chat
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isChatOpen]);

  // --- Cart & Customization Functions ---

  const openCustomizationModal = (item: MenuItem) => {
    setIsCustomizing(item);
    setCustomizationOptions([]);
    setCustomizationNotes('');
  };

  const toggleOption = (option: string) => {
    setCustomizationOptions(prev => 
      prev.includes(option) ? prev.filter(o => o !== option) : [...prev, option]
    );
  };

  const confirmAddToCart = () => {
    if (!isCustomizing) return;

    const newItem: CartItem = {
      ...isCustomizing,
      quantity: 1,
      cartId: Date.now().toString(), // Unique ID for this specific customization
      customizations: customizationOptions,
      notes: customizationNotes
    };

    setCart(prev => [...prev, newItem]);
    setIsCustomizing(null);
    setIsCartOpen(true);
  };

  const updateQuantity = (cartId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.cartId === cartId) {
        const newQty = item.quantity + delta;
        return newQty > 0 ? { ...item, quantity: newQty } : item;
      }
      return item;
    }));
  };

  const removeFromCart = (cartId: string) => {
    setCart(prev => prev.filter(i => i.cartId !== cartId));
  };

  const total = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalItems = cart.reduce((sum, item) => sum + item.quantity, 0);

  // --- Checkout Functions ---

  const handleCheckoutInput = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target;
    const checked = (e.target as HTMLInputElement).checked;

    setCheckoutForm(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));
  };

  const processPayment = (e: React.FormEvent) => {
    e.preventDefault();

    // Validation
    if (!checkoutForm.firstName || !checkoutForm.lastName || !checkoutForm.email || !checkoutForm.address || !checkoutForm.postalCode) {
      alert("Veuillez remplir tous les champs obligatoires.");
      return;
    }

    if (checkoutForm.paymentMethod === 'card') {
      if (!checkoutForm.cardName || !checkoutForm.cardNumber || !checkoutForm.cardExpiry || !checkoutForm.cardCVC) {
        alert("Veuillez remplir toutes les informations de votre carte de crédit.");
        return;
      }
    }

    setIsLoading(true);
    // Simulate API call
    setTimeout(() => {
      setIsLoading(false);
      alert(`Commande confirmée !\nMerci ${checkoutForm.firstName}.\nUn email de confirmation a été envoyé à ${checkoutForm.email}.`);
      setCart([]);
      setCurrentView('menu');
      setCheckoutForm({
        firstName: '', lastName: '', email: '', phone: '', address: '', postalCode: '',
        paymentMethod: 'card', savePayment: false, cardName: '', cardNumber: '', cardExpiry: '', cardCVC: ''
      });
    }, 1500);
  };

  // --- Subscription Logic ---
  const handleSubscriptionSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPlan || !subSalad || !subSandwich) return;

    const planName = selectedPlan === 'weekly' ? 'Hebdomadaire' : 'Quotidien';
    alert(`Félicitations ! Vous êtes abonné au plan ${planName}.\nVotre repas : ${salads.find(s=>s.id === subSalad)?.name} + ${sandwiches.find(s=>s.id === subSandwich)?.name}.`);
    setSelectedPlan(null);
    setSubSalad('');
    setSubSandwich('');
  };

  // --- Chat Functions ---
  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputMessage.trim() || !chatSessionRef.current) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: inputMessage
    };

    setMessages(prev => [...prev, userMsg]);
    setInputMessage('');
    setIsLoading(true);

    try {
      const result = await chatSessionRef.current.sendMessage({ message: userMsg.text });
      const modelMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: result.text
      };
      setMessages(prev => [...prev, modelMsg]);
    } catch (error) {
      console.error("Chat error:", error);
      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Oups, j'ai eu un petit problème de connexion. Réessaie !",
        isError: true
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-green-50 flex flex-col font-sans">
      {/* Navbar */}
      <nav className="bg-green-700 text-white shadow-lg sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-20 items-center">
            <div className="flex items-center gap-3 cursor-pointer" onClick={() => setCurrentView('menu')}>
              <div className="bg-white p-2 rounded-full shadow-md">
                <Leaf className="h-8 w-8 text-green-700 fill-current" />
              </div>
              <div className="flex flex-col">
                <span className="font-bold text-xl tracking-tight leading-none">Le Coin Étudiant</span>
                <span className="text-xs text-green-200 font-medium">Mange vert, reste fier</span>
              </div>
            </div>

            <div className="flex items-center gap-6">
              {currentView !== 'checkout' && (
                <div className="hidden md:flex gap-1 bg-green-800/50 p-1 rounded-lg">
                  <button 
                    onClick={() => setCurrentView('menu')}
                    className={`px-4 py-1.5 rounded-md text-sm font-semibold transition-all ${currentView === 'menu' ? 'bg-white text-green-800 shadow-sm' : 'text-green-100 hover:text-white'}`}
                  >
                    Carte
                  </button>
                  <button 
                    onClick={() => setCurrentView('subscription')}
                    className={`px-4 py-1.5 rounded-md text-sm font-semibold transition-all ${currentView === 'subscription' ? 'bg-white text-green-800 shadow-sm' : 'text-green-100 hover:text-white'}`}
                  >
                    Abonnements
                  </button>
                </div>
              )}

              {currentView !== 'checkout' && (
                <button 
                  onClick={() => setIsCartOpen(true)}
                  className="relative p-2 hover:bg-green-800 rounded-full transition-colors"
                >
                  <ShoppingCart className="h-7 w-7" />
                  {totalItems > 0 && (
                    <span className="absolute -top-1 -right-1 bg-yellow-400 text-green-900 text-xs font-bold w-5 h-5 flex items-center justify-center rounded-full border-2 border-green-700">
                      {totalItems}
                    </span>
                  )}
                </button>
              )}
            </div>
          </div>
          {/* Mobile Nav */}
          {currentView !== 'checkout' && (
            <div className="md:hidden flex justify-center pb-3 gap-4 text-sm font-medium">
               <button onClick={() => setCurrentView('menu')} className={`${currentView === 'menu' ? 'text-white underline decoration-2 underline-offset-4' : 'text-green-200'}`}>Carte</button>
               <button onClick={() => setCurrentView('subscription')} className={`${currentView === 'subscription' ? 'text-white underline decoration-2 underline-offset-4' : 'text-green-200'}`}>Abonnements</button>
            </div>
          )}
        </div>
      </nav>

      {/* Conditional Header based on View */}
      {currentView === 'checkout' ? (
        <div className="bg-white border-b border-green-100 py-6">
           <div className="max-w-7xl mx-auto px-4">
             <button onClick={() => setCurrentView('menu')} className="flex items-center text-green-600 hover:text-green-800 mb-4 font-medium transition-colors">
               <ArrowLeft className="h-4 w-4 mr-2" /> Retour au menu
             </button>
             <h1 className="text-3xl font-bold text-gray-900">Paiement Sécurisé</h1>
           </div>
        </div>
      ) : (
        <div className="bg-green-800 text-white py-12 px-4 sm:px-6 lg:px-8 relative overflow-hidden transition-all duration-500">
          <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none">
              <Leaf className="absolute -top-10 -left-10 w-64 h-64 rotate-12" />
              <Leaf className="absolute top-1/2 right-0 w-48 h-48 -rotate-45" />
          </div>

          <div className="max-w-7xl mx-auto text-center relative z-10">
            <h1 className="text-3xl sm:text-5xl font-extrabold mb-4 tracking-tight">
              {currentView === 'menu' ? (
                <>Nourris ton esprit,<br/>mange naturel.</>
              ) : (
                <>Simplifie ta vie,<br/>abonne-toi.</>
              )}
            </h1>
            <p className="text-green-100 text-lg sm:text-xl max-w-2xl mx-auto">
              {currentView === 'menu' 
                ? "Des repas frais et équilibrés pour te garder concentré toute la journée."
                : "Reçois ta combinaison préférée Salade + Sandwich automatiquement."}
            </p>
          </div>
        </div>
      )}

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10 flex-grow w-full">

        {currentView === 'menu' && (
          <>
            <h2 className="text-3xl font-bold text-green-900 mb-8 border-b-2 border-green-200 pb-3 inline-block">
              Notre Menu
            </h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {MENU_ITEMS.map((item) => (
                <div key={item.id} className="bg-white rounded-xl shadow-sm hover:shadow-lg transition-all duration-300 border border-green-100 flex flex-col overflow-hidden group">
                  <div className="p-6 flex flex-col flex-grow">
                    <div className="flex justify-between items-start mb-3">
                      <h3 className="text-xl font-bold text-green-900 leading-tight group-hover:text-green-700 transition-colors">{item.name}</h3>
                      <span className="bg-green-100 text-green-800 px-3 py-1 rounded-full text-sm font-bold shadow-sm whitespace-nowrap">
                       {item.price}$
                      </span>
                    </div>
                    <p className="text-gray-600 mb-6 flex-grow leading-relaxed">{item.description}</p>
                    <button
                      onClick={() => openCustomizationModal(item)}
                      className="w-full bg-green-50 hover:bg-green-100 text-green-700 font-bold py-3 px-4 rounded-lg flex items-center justify-center gap-2 transition-colors duration-200 border-2 border-green-100 hover:border-green-200"
                    >
                      <Plus className="h-5 w-5" />
                      Ajouter au panier
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </>
        )}

        {currentView === 'subscription' && (
          /* SUBSCRIPTION VIEW */
          <div className="max-w-4xl mx-auto">
             <h2 className="text-3xl font-bold text-green-900 mb-8 text-center">Choisis ton rythme</h2>
             <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-12">
               {/* Weekly Plan */}
               <div 
                 onClick={() => setSelectedPlan('weekly')}
                 className={`relative cursor-pointer rounded-2xl p-8 border-2 transition-all duration-300 flex flex-col ${selectedPlan === 'weekly' ? 'border-green-600 bg-green-50 shadow-xl scale-[1.02]' : 'border-gray-200 bg-white hover:border-green-300 hover:shadow-md'}`}
               >
                 {selectedPlan === 'weekly' && <div className="absolute top-4 right-4 text-green-600"><CheckCircle2 className="h-6 w-6" /></div>}
                 <div className="mb-4 bg-green-100 w-12 h-12 rounded-full flex items-center justify-center text-green-700">
                   <Calendar className="h-6 w-6" />
                 </div>
                 <h3 className="text-2xl font-bold text-gray-900 mb-2">Hebdomadaire</h3>
                 <p className="text-gray-500 mb-6">Un boost d'énergie pour ta semaine.</p>
                 <div className="mt-auto">
                   <span className="text-4xl font-extrabold text-green-700">15.99$</span>
                   <span className="text-gray-500 font-medium"> / semaine</span>
                 </div>
                 <ul className="mt-6 space-y-3 text-sm text-gray-600">
                   <li className="flex items-center gap-2"><CheckCircle2 className="h-4 w-4 text-green-500" /> 1 Salade au choix</li>
                   <li className="flex items-center gap-2"><CheckCircle2 className="h-4 w-4 text-green-500" /> 1 Sandwich au choix</li>
                   <li className="flex items-center gap-2"><CheckCircle2 className="h-4 w-4 text-green-500" /> Flexibilité totale</li>
                 </ul>
               </div>

               {/* Daily Plan */}
               <div 
                 onClick={() => setSelectedPlan('daily')}
                 className={`relative cursor-pointer rounded-2xl p-8 border-2 transition-all duration-300 flex flex-col ${selectedPlan === 'daily' ? 'border-green-600 bg-green-50 shadow-xl scale-[1.02]' : 'border-gray-200 bg-white hover:border-green-300 hover:shadow-md'}`}
               >
                 {selectedPlan === 'daily' && <div className="absolute top-4 right-4 text-green-600"><CheckCircle2 className="h-6 w-6" /></div>}
                 <div className="mb-4 bg-green-100 w-12 h-12 rounded-full flex items-center justify-center text-green-700">
                   <Leaf className="h-6 w-6" />
                 </div>
                 <h3 className="text-2xl font-bold text-gray-900 mb-2">Quotidien</h3>
                 <p className="text-gray-500 mb-6">La solution ultime sans cuisine.</p>
                 <div className="mt-auto">
                   <span className="text-4xl font-extrabold text-green-700">20.99$</span>
                   <span className="text-gray-500 font-medium"> / jour</span>
                 </div>
                 <ul className="mt-6 space-y-3 text-sm text-gray-600">
                   <li className="flex items-center gap-2"><CheckCircle2 className="h-4 w-4 text-green-500" /> 1 Salade par jour</li>
                   <li className="flex items-center gap-2"><CheckCircle2 className="h-4 w-4 text-green-500" /> 1 Sandwich par jour</li>
                   <li className="flex items-center gap-2"><CheckCircle2 className="h-4 w-4 text-green-500" /> Livraison prioritaire</li>
                 </ul>
               </div>
             </div>

             {/* Configuration Form */}
             {selectedPlan && (
               <div className="bg-white rounded-2xl shadow-lg border border-green-100 p-8 animate-in slide-in-from-bottom-5 duration-500">
                 <h3 className="text-xl font-bold text-green-900 mb-6 flex items-center gap-2">
