                    <input type="text" name="firstName" value={checkoutForm.firstName} onChange={handleCheckoutInput} className="w-full rounded-lg border-gray-300 border p-2.5 focus:ring-2 focus:ring-green-500 outline-none" placeholder="Jean" required />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Nom</label>
                    <input type="text" name="lastName" value={checkoutForm.lastName} onChange={handleCheckoutInput} className="w-full rounded-lg border-gray-300 border p-2.5 focus:ring-2 focus:ring-green-500 outline-none" placeholder="Dupont" required />
