                  <div className="md:col-span-2">
                    <label className="block text-sm font-medium text-gray-700 mb-1">
                      Téléphone <span className="text-gray-400 text-xs font-normal">(Optionnel)</span>
                    </label>
                    <div className="relative">
                      <Phone className="absolute left-3 top-3 h-5 w-5 text-gray-400" />
                      <input type="tel" name="phone" value={checkoutForm.phone} onChange={handleCheckoutInput} className="w-full rounded-lg border-gray-300 border p-2.5 pl-10 focus:ring-2 focus:ring-green-500 outline-none" placeholder="(514) 123-4567" />
                    </div>
                  </div>
                </div>
              </div>

              {/* Delivery Address */}
              <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                <h2 className="text-xl font-bold text-gray-800 mb-4 flex items-center gap-2">
                  <MapPin className="h-5 w-5 text-green-600" /> Adresse de livraison
                </h2>
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Adresse</label>
                    <input type="text" name="address" value={checkoutForm.address} onChange={handleCheckoutInput} className="w-full rounded-lg border-gray-300 border p-2.5 focus:ring-2 focus:ring-green-500 outline-none" placeholder="123 rue de l'Université" required />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Code Postal</label>
                    <input type="text" name="postalCode" value={checkoutForm.postalCode} onChange={handleCheckoutInput} className="w-32 rounded-lg border-gray-300 border p-2.5 focus:ring-2 focus:ring-green-500 outline-none" placeholder="H3C 1K3" required />
                  </div>
                </div>
              </div>

              {/* Payment */}
              <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                <h2 className="text-xl font-bold text-gray-800 mb-4 flex items-center gap-2">
                  <CreditCard className="h-5 w-5 text-green-600" /> Paiement
                </h2>

                <div className="flex gap-4 mb-6">
                  <label className={`flex-1 border rounded-lg p-4 cursor-pointer flex items-center gap-3 transition-colors ${checkoutForm.paymentMethod === 'card' ? 'border-green-500 bg-green-50 ring-1 ring-green-500' : 'border-gray-200 hover:border-gray-300'}`}>
                    <input type="radio" name="paymentMethod" value="card" checked={checkoutForm.paymentMethod === 'card'} onChange={handleCheckoutInput} className="accent-green-600" />
                    <span className="font-medium text-gray-800">Carte de Crédit</span>
                  </label>
                  <label className={`flex-1 border rounded-lg p-4 cursor-pointer flex items-center gap-3 transition-colors ${checkoutForm.paymentMethod === 'cash' ? 'border-green-500 bg-green-50 ring-1 ring-green-500' : 'border-gray-200 hover:border-gray-300'}`}>
                    <input type="radio" name="paymentMethod" value="cash" checked={checkoutForm.paymentMethod === 'cash'} onChange={handleCheckoutInput} className="accent-green-600" />
                    <span className="font-medium text-gray-800">Argent comptant / Sur place</span>
                  </label>
                </div>

                {checkoutForm.paymentMethod === 'card' && (
                  <div className="space-y-4 animate-in fade-in duration-300">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Nom complet sur la carte</label>
                      <input type="text" name="cardName" value={checkoutForm.cardName} onChange={handleCheckoutInput} className="w-full rounded-lg border-gray-300 border p-2.5 focus:ring-2 focus:ring-green-500 outline-none" placeholder="Jean Dupont" />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Numéro de carte</label>
                      <input type="text" name="cardNumber" value={checkoutForm.cardNumber} onChange={handleCheckoutInput} className="w-full rounded-lg border-gray-300 border p-2.5 focus:ring-2 focus:ring-green-500 outline-none" placeholder="0000 0000 0000 0000" />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Expiration</label>
                        <input type="text" name="cardExpiry" value={checkoutForm.cardExpiry} onChange={handleCheckoutInput} className="w-full rounded-lg border-gray-300 border p-2.5 focus:ring-2 focus:ring-green-500 outline-none" placeholder="MM/YY" />
                      </div>
                      <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">CVC</label>
                        <input type="text" name="cardCVC" value={checkoutForm.cardCVC} onChange={handleCheckoutInput} className="w-full rounded-lg border-gray-300 border p-2.5 focus:ring-2 focus:ring-green-500 outline-none" placeholder="123" />
                      </div>
                    </div>
                    <label className="flex items-center gap-2 mt-2 cursor-pointer">
                      <input type="checkbox" name="savePayment" checked={checkoutForm.savePayment} onChange={handleCheckoutInput} className="rounded text-green-600 focus:ring-green-500 w-4 h-4" />
                      <span className="text-sm text-gray-600">Sauvegarder ce mode de paiement pour la prochaine fois</span>
                    </label>
                  </div>
                )}
