      {/* Footer */}
      <footer className="bg-white border-t border-green-100 mt-12 py-10">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <div className="flex justify-center items-center gap-2 mb-4 text-green-700 font-bold">
