                          </>
                       ) : (
                          <>
                             {['Sauce à part', 'Sans croûtons', 'Sans fromage', 'Extra Vinaigrette'].map(opt => (
                               <label key={opt} className="flex items-center gap-3 p-2 rounded-lg hover:bg-green-50 cursor-pointer border border-transparent hover:border-green-100 transition-colors">
                                  <input 
                                    type="checkbox" 
                                    checked={customizationOptions.includes(opt)}
                                    onChange={() => toggleOption(opt)}
                                    className="w-5 h-5 rounded text-green-600 focus:ring-green-500 border-gray-300" 
                                  />
                                  <span className="text-gray-700">{opt}</span>
                               </label>
                             ))}
                          </>
                       )}
                    </div>
                  </div>

                  {/* Notes */}
                  <div>
                     <h4 className="font-semibold text-gray-700 mb-2">Instructions spéciales</h4>
                     <textarea 
                       className="w-full border border-gray-300 rounded-xl p-3 focus:ring-2 focus:ring-green-500 outline-none resize-none h-24 text-sm"
                       placeholder="Ex: Allergie aux arachides, couper en deux, etc..."
                       value={customizationNotes}
                       onChange={(e) => setCustomizationNotes(e.target.value)}
                     ></textarea>
                  </div>
                </div>

                <div className="mt-8 pt-4 border-t flex justify-end gap-3">
                   <button 
                     onClick={() => setIsCustomizing(null)}
                     className="px-5 py-2.5 rounded-xl font-medium text-gray-600 hover:bg-gray-100 transition-colors"
                   >
                     Annuler
                   </button>
                   <button 
                     onClick={confirmAddToCart}
                     className="px-6 py-2.5 rounded-xl font-bold bg-green-600 text-white hover:bg-green-700 transition-colors shadow-lg shadow-green-200"
                   >
                     Confirmer et Ajouter
                   </button>
                </div>
              </div>
           </div>
        </div>
      )}

      {/* Cart Sidebar */}
      {isCartOpen && (
        <div className="fixed inset-0 z-50 overflow-hidden">
          <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setIsCartOpen(false)} />
          <div className="absolute inset-y-0 right-0 max-w-full flex">
            <div className="w-screen max-w-md bg-white shadow-2xl flex flex-col h-full transform transition-transform duration-300">
              <div className="flex items-center justify-between p-5 border-b border-green-100 bg-green-50">
                <h2 className="text-xl font-bold text-green-900 flex items-center gap-2">
                  <ShoppingCart className="h-6 w-6 text-green-700" />
                  Ton Panier
                </h2>
                <button onClick={() => setIsCartOpen(false)} className="text-gray-500 hover:text-green-700 transition-colors">
                  <X className="h-6 w-6" />
                </button>
              </div>

              <div className="flex-1 overflow-y-auto p-5 space-y-4">
                {cart.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center text-gray-400">
                    <Leaf className="h-16 w-16 mb-4 text-green-200" />
                    <p className="text-lg font-medium text-gray-500">Ton panier est vide.</p>
                    <button 
                      onClick={() => {setIsCartOpen(false); setCurrentView('menu');}}
                      className="mt-4 text-green-600 font-bold hover:underline"
                    >
                      Voir le menu
                    </button>
                  </div>
                ) : (
                  cart.map(item => (
                    <div key={item.cartId} className="flex gap-4 p-4 bg-green-50/50 rounded-xl border border-green-100 hover:border-green-200 transition-colors">
                      <div className="flex-1">
                        <h3 className="font-bold text-gray-900 text-base mb-1">{item.name}</h3>

                        {/* Customizations display */}
                        {(item.customizations?.length || 0) > 0 && (
                          <div className="flex flex-wrap gap-1 mb-2">
                             {item.customizations?.map(c => (
                               <span key={c} className="text-[10px] bg-white border border-green-100 text-green-700 px-1.5 py-0.5 rounded-full">{c}</span>
                             ))}
                          </div>
                        )}
                         {item.notes && (
                            <p className="text-xs text-gray-500 italic mb-2">"{item.notes}"</p>
                        )}

                        <div className="flex items-center justify-between">
                            <p className="text-green-700 font-bold">{item.price}$</p>
                            <div className="flex items-center gap-3">
                              <button 
                                onClick={() => updateQuantity(item.cartId, -1)}
                                className="p-1.5 rounded-full bg-white border border-green-200 hover:bg-green-100 text-green-700 shadow-sm"
                              >
                                <Minus className="h-3 w-3" />
                              </button>
                              <span className="text-sm font-bold w-4 text-center text-gray-800">{item.quantity}</span>
                              <button 
                                onClick={() => updateQuantity(item.cartId, 1)}
                                className="p-1.5 rounded-full bg-white border border-green-200 hover:bg-green-100 text-green-700 shadow-sm"
                              >
                                <Plus className="h-3 w-3" />
                              </button>
                            </div>
                        </div>
                      </div>
                      <button 
                        onClick={() => removeFromCart(item.cartId)}
                        className="text-gray-400 hover:text-red-500 self-start p-1"
                      >
                        <Trash2 className="h-5 w-5" />
                      </button>
                    </div>
                  ))
                )}
              </div>

              {cart.length > 0 && (
                <div className="border-t border-green-100 p-6 bg-green-50">
                  <div className="flex justify-between items-center mb-6">
                    <span className="text-gray-600 font-medium">Total à payer</span>
                    <span className="text-3xl font-extrabold text-green-900">{total.toFixed(2)}$</span>
                  </div>
                  <button 
                    onClick={() => {
                      setIsCartOpen(false);
                      setCurrentView('checkout');
                    }}
                    className="w-full bg-green-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-green-700 active:scale-[0.98] transition-all shadow-lg shadow-green-200"
                  >
                    Commander maintenant
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* AI Chat Widget */}
      <div className="fixed bottom-6 right-6 z-40 flex flex-col items-end pointer-events-none">
        {isChatOpen && (
          <div className="pointer-events-auto mb-4 w-80 sm:w-96 bg-white rounded-2xl shadow-2xl border border-green-100 overflow-hidden flex flex-col max-h-[500px] animate-in slide-in-from-bottom-5 duration-200">
            <div className="bg-green-600 p-4 flex justify-between items-center text-white">
              <div className="flex items-center gap-2">
                <MessageSquare className="h-5 w-5" />
                <span className="font-bold">Assistant Gourmand</span>
              </div>
              <button onClick={() => setIsChatOpen(false)} className="hover:bg-green-700 p-1 rounded-full transition-colors">
                <X className="h-4 w-4" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-green-50/50 h-80">
              {messages.map((msg) => (
                <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] p-3.5 rounded-2xl text-sm leading-relaxed ${
                    msg.role === 'user' 
                      ? 'bg-green-600 text-white rounded-br-sm shadow-md' 
                      : 'bg-white border border-gray-200 text-gray-800 rounded-bl-sm shadow-sm'
                  }`}>
                    {msg.text}
                  </div>
                </div>
              ))}
              {isLoading && (
                <div className="flex justify-start">
                  <div className="bg-white border border-gray-200 p-3 rounded-2xl rounded-bl-sm shadow-sm flex items-center gap-2">
                    <Loader2 className="h-4 w-4 animate-spin text-green-600" />
                    <span className="text-xs text-gray-500 font-medium">Réflexion en cours...</span>
                  </div>
                </div>
              )}
              <div ref={chatEndRef} />
            </div>

            <form onSubmit={handleSendMessage} className="p-3 bg-white border-t border-gray-100 flex gap-2">
              <input
                type="text"
                value={inputMessage}
                onChange={(e) => setInputMessage(e.target.value)}
                placeholder="Ex: Quel est le meilleur abonnement ?"
                className="flex-1 bg-gray-100 text-gray-900 border-0 rounded-full px-4 py-2 focus:ring-2 focus:ring-green-500 text-sm transition-shadow"
              />
              <button 
                type="submit" 
                disabled={isLoading || !inputMessage.trim()}
                className="bg-green-600 text-white p-2.5 rounded-full hover:bg-green-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors shadow-md"
              >
                <Send className="h-4 w-4" />
              </button>
            </form>
          </div>
        )}

        <button
          onClick={() => setIsChatOpen(!isChatOpen)}
          className="pointer-events-auto bg-green-600 hover:bg-green-700 text-white p-4 rounded-full shadow-xl hover:shadow-2xl hover:shadow-green-900/20 transition-all duration-200 transform hover:scale-110 active:scale-95 flex items-center justify-center group"
        >
          {isChatOpen ? <X className="h-6 w-6" /> : <MessageSquare className="h-6 w-6" />}
          {!isChatOpen && (
            <span className="absolute right-full mr-4 bg-white text-gray-800 px-4 py-2 rounded-lg text-sm font-bold shadow-md whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none border border-green-100 text-green-800">
              Besoin d'aide ?
            </span>
          )}
        </button>
      </div>
    </div>
  );
}

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { ShoppingCart, X, MessageSquare, Send, Plus, Minus, Trash2, Leaf, Loader2, Calendar, CheckCircle2, ArrowRight, ArrowLeft, MapPin, CreditCard, User, Mail, Phone, Edit3, Lock, LogOut } from 'lucide-react';
import { GoogleGenAI, Chat } from "@google/genai";
import { MENU_ITEMS } from './constants';
import { CartItem, MenuItem, ChatMessage } from './types';

// Initialize Gemini API
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

function App() {
  // Auth State
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loginData, setLoginData] = useState({
    firstName: '',
    lastName: '',
    phone: '',
    email: '',
    password: '',
    rememberMe: false
  });

  // Navigation State
  const [currentView, setCurrentView] = useState<'menu' | 'subscription' | 'checkout'>('menu');

  // Shop State
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);

  // Customization State
  const [isCustomizing, setIsCustomizing] = useState<MenuItem | null>(null);
  const [customizationOptions, setCustomizationOptions] = useState<string[]>([]);
  const [customizationNotes, setCustomizationNotes] = useState('');

  // Checkout Form State
  const [checkoutForm, setCheckoutForm] = useState({
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    address: '',
    postalCode: '',
    paymentMethod: 'card', // 'card' or 'cash'
    savePayment: false,
    cardName: '',
    cardNumber: '',
    cardExpiry: '',
    cardCVC: ''
  });

  // Chat State
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: 'welcome', role: 'model', text: 'Salut ! Bienvenue au Coin Étudiant. Besoin d\'aide pour choisir un repas ou un abonnement ?' }
  ]);
  const [inputMessage, setInputMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  // Subscription State
  const [selectedPlan, setSelectedPlan] = useState<'weekly' | 'daily' | null>(null);
  const [subSalad, setSubSalad] = useState<string>('');
  const [subSandwich, setSubSandwich] = useState<string>('');

  // Refs
  const chatEndRef = useRef<HTMLDivElement>(null);
  const chatSessionRef = useRef<Chat | null>(null);

  // Derived Data
  const salads = MENU_ITEMS.filter(item => item.category === 'salad');
  const sandwiches = MENU_ITEMS.filter(item => item.category === 'sandwich');

  // Check for saved user on mount
  useEffect(() => {
    const savedUser = localStorage.getItem('auth_user');
    if (savedUser) {
      try {
        const user = JSON.parse(savedUser);
        setLoginData(prev => ({ ...prev, ...user, password: '' }));
        // Pre-fill checkout form with saved data
        setCheckoutForm(prev => ({
          ...prev,
          firstName: user.firstName || '',
          lastName: user.lastName || '',
          email: user.email || '',
          phone: user.phone || ''
        }));
        setIsAuthenticated(true);
      } catch (e) {
        console.error("Error parsing saved user", e);
        localStorage.removeItem('auth_user');
      }
    }
  }, []);

  // Initialize Chat Session
  useEffect(() => {
    if (!isAuthenticated) return; 

    const menuContext = MENU_ITEMS.map(item => 
      `- ${item.name} (${item.price}$): ${item.description}`
    ).join('\n');

    const systemInstruction = `Tu es un assistant amical pour "Le Coin Étudiant".
    Le style du restaurant est "Natural Food", vert et santé.
    Ta mission est d'aider les étudiants à choisir leur repas ou leur abonnement.

    MENU :
    ${menuContext}

    ABONNEMENTS DISPONIBLES :
    1. Abonnement Hebdomadaire (15.99$ / semaine) : Reçois 1 repas (1 Salade + 1 Sandwich) chaque semaine.
    2. Abonnement Quotidien (20.99$ / jour) : Reçois 1 repas (1 Salade + 1 Sandwich) chaque jour.

    Règles :
    1. Réponds toujours en français.
    2. Sois concis, jeune et dynamique.
    3. Si l'utilisateur parle d'économiser ou de régularité, propose les abonnements.
    4. Mets l'accent sur la fraîcheur.
    `;

    chatSessionRef.current = ai.chats.create({
      model: 'gemini-2.5-flash',
      config: {
        systemInstruction,
        temperature: 0.7,
      }
    });
  }, [isAuthenticated]);

  // Scroll to bottom of chat
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isChatOpen]);

  // --- Login Functions ---
  const handleLoginInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type, checked } = e.target;
    setLoginData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));
  };

  const handleLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Basic validation
    if (!loginData.firstName || !loginData.lastName || !loginData.email || !loginData.password) {
      alert("Veuillez remplir tous les champs obligatoires (Prénom, Nom, Email, Mot de passe).");
      return;
    }

    // Save to local storage if remember me is checked
    if (loginData.rememberMe) {
      localStorage.setItem('auth_user', JSON.stringify({
        firstName: loginData.firstName,
        lastName: loginData.lastName,
        email: loginData.email,
