  const [subSalad, setSubSalad] = useState<string>('');
  const [subSandwich, setSubSandwich] = useState<string>('');

  // Refs
  const chatEndRef = useRef<HTMLDivElement>(null);
  const chatSessionRef = useRef<Chat | null>(null);

  // Derived Data
  const salads = MENU_ITEMS.filter(item => item.category === 'salad');
  const sandwiches = MENU_ITEMS.filter(item => item.category === 'sandwich');

  // Check for saved user on mount
  useEffect(() => {
    const savedUser = localStorage.getItem('auth_user');
    if (savedUser) {
      try {
        const user = JSON.parse(savedUser);
        setLoginData(prev => ({ ...prev, ...user, password: '' }));
        // Pre-fill checkout form with saved data
        setCheckoutForm(prev => ({
          ...prev,
          firstName: user.firstName || '',
          lastName: user.lastName || '',
          email: user.email || '',
          phone: user.phone || ''
        }));
        setIsAuthenticated(true);
      } catch (e) {
        console.error("Error parsing saved user", e);
        localStorage.removeItem('auth_user');
      }
    }
  }, []);

  // Initialize Chat Session
  useEffect(() => {
    if (!isAuthenticated) return; 

    const menuContext = MENU_ITEMS.map(item => 
      `- ${item.name} (${item.price}$): ${item.description}`
    ).join('\n');

    const systemInstruction = `Tu es un assistant amical pour "Le Coin Étudiant".
    Le style du restaurant est "Natural Food", vert et santé.
    Ta mission est d'aider les étudiants à choisir leur repas ou leur abonnement.

    MENU :
    ${menuContext}

    ABONNEMENTS DISPONIBLES :
    1. Abonnement Hebdomadaire (15.99$ / semaine) : Reçois 1 repas (1 Salade + 1 Sandwich) chaque semaine.
    2. Abonnement Quotidien (20.99$ / semaine) : Reçois 1 repas (1 Salade + 1 Sandwich) chaque jour.

    Règles :
    1. Réponds toujours en français.
    2. Sois concis, jeune et dynamique.
    3. Si l'utilisateur parle d'économiser ou de régularité, propose les abonnements.
    4. Mets l'accent sur la fraîcheur.
    `;

    chatSessionRef.current = ai.chats.create({
      model: 'gemini-2.5-flash',
      config: {
        systemInstruction,
        temperature: 0.7,
      }
    });
  }, [isAuthenticated]);

  // Scroll to bottom of chat
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isChatOpen]);

  // --- Login Functions ---
  const handleLoginInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type, checked } = e.target;
    setLoginData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
