  ]);
  const [inputMessage, setInputMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  // Meal Assistant State
  const [assistantGoal, setAssistantGoal] = useState('');
  const [assistantResponse, setAssistantResponse] = useState<string | null>(null);
  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);

  // Subscription State
  const [selectedPlan, setSelectedPlan] = useState<'weekly' | 'daily' | null>(null);
  const [subSalad, setSubSalad] = useState<string>('');
  const [subSandwich, setSubSandwich] = useState<string>('');

  // Refs
  const chatEndRef = useRef<HTMLDivElement>(null);
  const chatSessionRef = useRef<Chat | null>(null);

  // Derived Data
  const salads = MENU_ITEMS.filter(item => item.category === 'salad');
  const sandwiches = MENU_ITEMS.filter(item => item.category === 'sandwich');

  // Check for saved user on mount
  useEffect(() => {
    const savedUser = localStorage.getItem('auth_user');
    if (savedUser) {
      try {
        const user = JSON.parse(savedUser);
        setLoginData(prev => ({ ...prev, ...user, password: '' }));
        // Pre-fill checkout form with saved data
        setCheckoutForm(prev => ({
          ...prev,
          firstName: user.firstName || '',
          lastName: user.lastName || '',
          email: user.email || '',
          phone: user.phone || ''
        }));
        setIsAuthenticated(true);
      } catch (e) {
        console.error("Error parsing saved user", e);
        localStorage.removeItem('auth_user');
      }
    }
  }, []);

  // Initialize Chat Session
  useEffect(() => {
    if (!isAuthenticated) return; 

    const menuContext = MENU_ITEMS.map(item => 
      `- ${item.name} (${item.price}$): ${item.description}`
    ).join('\n');

    const systemInstruction = `Tu es un assistant amical pour "Le Coin Étudiant".
    Le style du restaurant est "Natural Food", vert et santé.
    Ta mission est d'aider les étudiants à choisir leur repas ou leur abonnement.

    MENU :
    ${menuContext}

    ABONNEMENTS DISPONIBLES :
    1. Abonnement Hebdomadaire (15.99$ / semaine) : Reçois 1 repas (1 Salade + 1 Sandwich) chaque semaine.
    2. Abonnement Quotidien (20.99$ / semaine) : Reçois 1 repas (1 Salade + 1 Sandwich) chaque jour.

    Règles :
    1. Réponds toujours en français.
    2. Sois concis, jeune et dynamique.
    3. Si l'utilisateur parle d'économiser ou de régularité, propose les abonnements.
    4. Mets l'accent sur la fraîcheur.
    `;

    chatSessionRef.current = ai.chats.create({
      model: 'gemini-2.5-flash',
      config: {
        systemInstruction,
        temperature: 0.7,
      }
    });
  }, [isAuthenticated]);

  // Scroll to bottom of chat
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isChatOpen]);

  // --- Login Functions ---
  const handleLoginInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type, checked } = e.target;
    setLoginData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));
  };

  const handleLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Basic validation
    if (!loginData.firstName || !loginData.lastName || !loginData.email || !loginData.password) {
      alert("Veuillez remplir tous les champs obligatoires (Prénom, Nom, Email, Mot de passe).");
      return;
    }

    // Save to local storage if remember me is checked
    if (loginData.rememberMe) {
      localStorage.setItem('auth_user', JSON.stringify({
        firstName: loginData.firstName,
        lastName: loginData.lastName,
        email: loginData.email,
        phone: loginData.phone
      }));
    } else {
      localStorage.removeItem('auth_user');
    }

    // Populate checkout form with login data
    setCheckoutForm(prev => ({
      ...prev,
      firstName: loginData.firstName,
      lastName: loginData.lastName,
      email: loginData.email,
      phone: loginData.phone
    }));

    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCart([]);
    setCurrentView('menu');
    localStorage.removeItem('auth_user');
    setLoginData({
      firstName: '', lastName: '', phone: '', email: '', password: '', rememberMe: false
    });
  };

  // --- Cart & Customization Functions ---

  const openCustomizationModal = (item: MenuItem) => {
    setIsCustomizing(item);
    setCustomizationOptions([]);
    setCustomizationNotes('');
  };

  const toggleOption = (option: string) => {
    setCustomizationOptions(prev => 
      prev.includes(option) ? prev.filter(o => o !== option) : [...prev, option]
    );
  };

  const confirmAddToCart = () => {
    if (!isCustomizing) return;

    const newItem: CartItem = {
      ...isCustomizing,
      quantity: 1,
      cartId: Date.now().toString(), // Unique ID for this specific customization
      customizations: customizationOptions,
      notes: customizationNotes
    };

    setCart(prev => [...prev, newItem]);
    setIsCustomizing(null);
    setIsCartOpen(true);
  };

  const updateQuantity = (cartId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.cartId === cartId) {
        const newQty = item.quantity + delta;
        return newQty > 0 ? { ...item, quantity: newQty } : item;
      }
      return item;
    }));
  };

  const removeFromCart = (cartId: string) => {
    setCart(prev => prev.filter(i => i.cartId !== cartId));
  };

  const total = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalItems = cart.reduce((sum, item) => sum + item.quantity, 0);

  // --- Checkout Functions ---

  const handleCheckoutInput = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target;
    const checked = (e.target as HTMLInputElement).checked;

    setCheckoutForm(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));
  };

  const processPayment = (e: React.FormEvent) => {
    e.preventDefault();

    // Validation
    if (!checkoutForm.firstName || !checkoutForm.lastName || !checkoutForm.email || !checkoutForm.address || !checkoutForm.postalCode) {
      alert("Veuillez remplir tous les champs obligatoires.");
      return;
    }

    if (checkoutForm.paymentMethod === 'card') {
      if (!checkoutForm.cardName || !checkoutForm.cardNumber || !checkoutForm.cardExpiry || !checkoutForm.cardCVC) {
        alert("Veuillez remplir toutes les informations de votre carte de crédit.");
        return;
      }
    }

    setIsLoading(true);
    // Simulate API call
    setTimeout(() => {
      setIsLoading(false);
      alert(`Commande confirmée !\nMerci ${checkoutForm.firstName}.\nUn email de confirmation a été envoyé à ${checkoutForm.email}.`);
      setCart([]);
      setCurrentView('menu');
      // Reset sensitive data but keep user info
      setCheckoutForm(prev => ({
        ...prev,
        paymentMethod: 'card', savePayment: false, cardName: '', cardNumber: '', cardExpiry: '', cardCVC: ''
      }));
    }, 1500);
  };

  // --- Subscription Logic ---
  const handleSubscriptionSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPlan || !subSalad || !subSandwich) return;

    const planName = selectedPlan === 'weekly' ? 'Hebdomadaire' : 'Quotidien';
    alert(`Félicitations ! Vous êtes abonné au plan ${planName}.\nVotre repas : ${salads.find(s=>s.id === subSalad)?.name} + ${sandwiches.find(s=>s.id === subSandwich)?.name}.`);
    setSelectedPlan(null);
    setSubSalad('');
    setSubSandwich('');
  };

  // --- Chat Functions ---
  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputMessage.trim() || !chatSessionRef.current) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: inputMessage
    };

    setMessages(prev => [...prev, userMsg]);
    setInputMessage('');
    setIsLoading(true);

    try {
      const result = await chatSessionRef.current.sendMessage({ message: userMsg.text });
      const modelMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: result.text
      };
      setMessages(prev => [...prev, modelMsg]);
    } catch (error) {
      console.error("Chat error:", error);
      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Oups, j'ai eu un petit problème de connexion. Réessaie !",
        isError: true
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  // --- Meal Assistant Functions ---
  const handleGeneratePlan = async (e: React.FormEvent) => {
    e.preventDefault();
    if(!assistantGoal.trim()) return;

    setIsGeneratingPlan(true);
    setAssistantResponse(null);

    const menuData = JSON.stringify(MENU_ITEMS);
    const prompt = `
      User Goal: "${assistantGoal}"

      You are the expert Nutritionist AI for "Le Coin Étudiant".
      Analyze the user's goal.
      Select 2-3 specific items from the menu below that perfectly match their goal (e.g. high protein, low carb, energy boost).

      CRITICAL INSTRUCTION:
      Unless the user explicitly asks for a "single meal" or "one time order", you MUST recommend a SUBSCRIPTION plan (Daily or Weekly) as the primary solution.
      Argue that consistency is key to achieving their goal (building muscle, studying better, saving money) and that the subscription is the best way to do it.

      Menu Data: ${menuData}

      Subscriptions:
      - Weekly: $15.99 / week (1 meal/week)
      - Daily: $20.99 / week (1 meal/DAY - This is an amazing deal, emphasize value!)

      Format the output nicely with clear headings (Markdown style). Be persuasive, energetic, and encouraging. Use emojis.
      Answer in French.
    `;

    try {
      // Using gemini-3-pro-preview for complex reasoning and persuasion
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt
      });
      setAssistantResponse(response.text || "Désolé, je n'ai pas pu générer de plan pour le moment.");
    } catch (error) {
      console.error("Assistant error", error);
      setAssistantResponse("Une erreur est survenue lors de la communication avec l'assistant.");
    } finally {
      setIsGeneratingPlan(false);
    }
  };


  // --- Login View ---
  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-green-50 flex flex-col justify-center items-center p-4 font-sans">
        <div className="max-w-md w-full bg-white rounded-2xl shadow-xl overflow-hidden border border-green-100">
          <div className="bg-green-700 p-8 text-center">
            <div className="bg-white p-3 rounded-full shadow-md inline-block mb-4">
              <Leaf className="h-10 w-10 text-green-700 fill-current" />
            </div>
            <h1 className="text-2xl font-bold text-white mb-2">Le Coin Étudiant</h1>
            <p className="text-green-100">Connectez-vous pour commander</p>
          </div>

          <div className="p-8">
            <form onSubmit={handleLoginSubmit} className="space-y-5">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Prénom</label>
                  <div className="relative">
                    <User className="absolute left-3 top-3 h-5 w-5 text-gray-400" />
                    <input
                      type="text"
                      name="firstName"
                      value={loginData.firstName}
                      onChange={handleLoginInput}
                      className="w-full pl-10 pr-4 py-2 bg-transparent border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 outline-none"
                      placeholder="Jean"
                      required
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Nom</label>
                  <input
                    type="text"
                    name="lastName"
                    value={loginData.lastName}
                    onChange={handleLoginInput}
                    className="w-full px-4 py-2 bg-transparent border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 outline-none"
                    placeholder="Dupont"
                    required
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Email</label>
                <div className="relative">
                  <Mail className="absolute left-3 top-3 h-5 w-5 text-gray-400" />
                  <input
                    type="email"
                    name="email"
                    value={loginData.email}
                    onChange={handleLoginInput}
                    className="w-full pl-10 pr-4 py-2 bg-transparent border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 outline-none"
                    placeholder="etudiant@universite.ca"
                    required
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Téléphone <span className="text-gray-400 text-xs font-normal">(Optionnel)</span>
                </label>
                <div className="relative">
                  <Phone className="absolute left-3 top-3 h-5 w-5 text-gray-400" />
                  <input
                    type="tel"
                    name="phone"
                    value={loginData.phone}
                    onChange={handleLoginInput}
                    className="w-full pl-10 pr-4 py-2 bg-transparent border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 outline-none"
                    placeholder="(555) 123-4567"
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Mot de passe</label>
                <div className="relative">
                  <Lock className="absolute left-3 top-3 h-5 w-5 text-gray-400" />
                  <input
                    type="password"
                    name="password"
                    value={loginData.password}
                    onChange={handleLoginInput}
                    className="w-full pl-10 pr-4 py-2 bg-transparent border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 outline-none"
                    placeholder="••••••••"
                    required
                  />
                </div>
              </div>

              <div className="flex items-center">
                <input
                  id="remember-me"
                  name="rememberMe"
                  type="checkbox"
                  checked={loginData.rememberMe}
                  onChange={handleLoginInput}
                  className="h-4 w-4 text-green-600 focus:ring-green-500 border-gray-300 rounded"
                />
                <label htmlFor="remember-me" className="ml-2 block text-sm text-gray-900">
                  Se souvenir de moi la prochaine fois
                </label>
              </div>

              <button
                type="submit"
                className="w-full flex justify-center py-3 px-4 border border-transparent rounded-xl shadow-sm text-sm font-bold text-white bg-green-600 hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 transition-colors"
              >
                Accéder à l'application
              </button>
            </form>
          </div>
          <div className="bg-gray-50 px-8 py-4 border-t border-gray-100 text-center">
            <p className="text-xs text-gray-500">En vous connectant, vous acceptez nos conditions d'utilisation.</p>
          </div>
        </div>
      </div>
    );
  }

  // --- Main App View ---
  return (
    <div className="min-h-screen bg-green-50 flex flex-col font-sans">
      {/* Navbar */}
      <nav className="bg-green-700 text-white shadow-lg sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-20 items-center">
            <div className="flex items-center gap-3 cursor-pointer" onClick={() => setCurrentView('menu')}>
              <div className="bg-white p-2 rounded-full shadow-md">
                <Leaf className="h-8 w-8 text-green-700 fill-current" />
              </div>
              <div className="flex flex-col">
                <span className="font-bold text-xl tracking-tight leading-none">Le Coin Étudiant</span>
                <span className="text-xs text-green-200 font-medium">Mange vert, reste fier</span>
              </div>
            </div>

            <div className="flex items-center gap-4 md:gap-6">
              {currentView !== 'checkout' && (
                <div className="hidden md:flex gap-1 bg-green-800/50 p-1 rounded-lg">
                  <button 
                    onClick={() => setCurrentView('menu')}
                    className={`px-4 py-1.5 rounded-md text-sm font-semibold transition-all ${currentView === 'menu' ? 'bg-white text-green-800 shadow-sm' : 'text-green-100 hover:text-white'}`}
                  >
                    Carte
                  </button>
                  <button 
                    onClick={() => setCurrentView('subscription')}
                    className={`px-4 py-1.5 rounded-md text-sm font-semibold transition-all ${currentView === 'subscription' ? 'bg-white text-green-800 shadow-sm' : 'text-green-100 hover:text-white'}`}
                  >
                    Abonnements
                  </button>
                   <button 
                    onClick={() => setCurrentView('assistant')}
                    className={`px-4 py-1.5 rounded-md text-sm font-semibold transition-all flex items-center gap-2 ${currentView === 'assistant' ? 'bg-white text-green-800 shadow-sm' : 'text-green-100 hover:text-white'}`}
                  >
                    <Sparkles className="h-4 w-4" />
                    Assistant Santé
                  </button>
                </div>
              )}

              <div className="flex items-center gap-2 md:gap-4">
                <div className="hidden md:flex flex-col items-end mr-2">
                  <span className="text-sm font-bold leading-none">{loginData.firstName} {loginData.lastName}</span>
                  <span className="text-xs text-green-200 cursor-pointer hover:underline" onClick={handleLogout}>Se déconnecter</span>
                </div>

                {currentView !== 'checkout' && (
                  <button 
                    onClick={() => setIsCartOpen(true)}
                    className="relative p-2 hover:bg-green-800 rounded-full transition-colors"
                  >
                    <ShoppingCart className="h-7 w-7" />
                    {totalItems > 0 && (
                      <span className="absolute -top-1 -right-1 bg-yellow-400 text-green-900 text-xs font-bold w-5 h-5 flex items-center justify-center rounded-full border-2 border-green-700">
                        {totalItems}
                      </span>
                    )}
                  </button>
                )}

                <button 
                  onClick={handleLogout}
                  className="md:hidden p-2 hover:bg-green-800 rounded-full transition-colors"
                  title="Se déconnecter"
                >
                  <LogOut className="h-6 w-6" />
                </button>
              </div>
            </div>
          </div>
          {/* Mobile Nav */}
          {currentView !== 'checkout' && (
            <div className="md:hidden flex justify-center pb-3 gap-4 text-sm font-medium">
               <button onClick={() => setCurrentView('menu')} className={`${currentView === 'menu' ? 'text-white underline decoration-2 underline-offset-4' : 'text-green-200'}`}>Carte</button>
               <button onClick={() => setCurrentView('subscription')} className={`${currentView === 'subscription' ? 'text-white underline decoration-2 underline-offset-4' : 'text-green-200'}`}>Abonnements</button>
               <button onClick={() => setCurrentView('assistant')} className={`${currentView === 'assistant' ? 'text-white underline decoration-2 underline-offset-4' : 'text-green-200'}`}>Assistant</button>
            </div>
          )}
        </div>
      </nav>

      {/* Conditional Header based on View */}
      {currentView === 'checkout' ? (
        <div className="bg-white border-b border-green-100 py-6">
           <div className="max-w-7xl mx-auto px-4">
             <button onClick={() => setCurrentView('menu')} className="flex items-center text-green-600 hover:text-green-800 mb-4 font-medium transition-colors">
               <ArrowLeft className="h-4 w-4 mr-2" /> Retour au menu
             </button>
             <h1 className="text-3xl font-bold text-gray-900">Paiement Sécurisé</h1>
           </div>
        </div>
      ) : (
        <div className="bg-green-800 text-white py-12 px-4 sm:px-6 lg:px-8 relative overflow-hidden transition-all duration-500">
          <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none">
              <Leaf className="absolute -top-10 -left-10 w-64 h-64 rotate-12" />
              <Leaf className="absolute top-1/2 right-0 w-48 h-48 -rotate-45" />
          </div>

          <div className="max-w-7xl mx-auto text-center relative z-10">
            <h1 className="text-3xl sm:text-5xl font-extrabold mb-4 tracking-tight">
              {currentView === 'menu' ? (
                <>Nourris ton esprit,<br/>mange naturel.</>
              ) : currentView === 'subscription' ? (
                <>Simplifie ta vie,<br/>abonne-toi.</>
              ) : (
                <>Tes objectifs,<br/>notre carburant.</>
              )}
            </h1>
            <p className="text-green-100 text-lg sm:text-xl max-w-2xl mx-auto">
              {currentView === 'menu' 
                ? "Des repas frais et équilibrés pour te garder concentré toute la journée."
                : currentView === 'subscription' 
                ? "Reçois ta combinaison préférée Salade + Sandwich automatiquement."
                : "Dis-nous ce que tu veux accomplir, et l'IA créera ton plan idéal."}
            </p>
          </div>
        </div>
      )}

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10 flex-grow w-full">

        {currentView === 'menu' && (
          <>
            <h2 className="text-3xl font-bold text-green-900 mb-8 border-b-2 border-green-200 pb-3 inline-block">
              Notre Menu
            </h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {MENU_ITEMS.map((item) => (
                <div key={item.id} className="bg-white rounded-xl shadow-sm hover:shadow-lg transition-all duration-300 border border-green-100 flex flex-col overflow-hidden group">
                  <div className="p-6 flex flex-col flex-grow">
                    <div className="flex justify-between items-start mb-3">
                      <h3 className="text-xl font-bold text-green-900 leading-tight group-hover:text-green-700 transition-colors">{item.name}</h3>
                      <span className="bg-green-100 text-green-800 px-3 py-1 rounded-full text-sm font-bold shadow-sm whitespace-nowrap">
                       {item.price}$
                      </span>
                    </div>
                    <p className="text-gray-600 mb-6 flex-grow leading-relaxed">{item.description}</p>
                    <button
                      onClick={() => openCustomizationModal(item)}
                      className="w-full bg-green-50 hover:bg-green-100 text-green-700 font-bold py-3 px-4 rounded-lg flex items-center justify-center gap-2 transition-colors duration-200 border-2 border-green-100 hover:border-green-200"
                    >
                      <Plus className="h-5 w-5" />
                      Ajouter au panier
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </>
        )}

        {currentView === 'assistant' && (
           <div className="max-w-3xl mx-auto">
              <div className="bg-white rounded-2xl shadow-xl border border-green-100 overflow-hidden">
                 <div className="p-8 bg-green-50/50 border-b border-green-100">
                    <div className="flex items-center gap-3 mb-6">
                       <div className="bg-green-100 p-3 rounded-full text-green-700">
                          <Activity className="h-6 w-6" />
                       </div>
                       <h2 className="text-2xl font-bold text-green-900">Coach Nutrition IA</h2>
                    </div>

                    <form onSubmit={handleGeneratePlan} className="space-y-4">
                       <div>
                          <label className="block text-sm font-medium text-gray-700 mb-2">Quels sont tes objectifs de santé ou tes besoins actuels ?</label>
                          <textarea
                             value={assistantGoal}
                             onChange={(e) => setAssistantGoal(e.target.value)}
                             placeholder="Ex: Je veux prendre de la masse musculaire et j'ai un budget serré..."
                             className="w-full bg-white border border-green-200 rounded-xl p-4 h-32 focus:ring-2 focus:ring-green-500 outline-none resize-none shadow-sm text-gray-700"
                          />
                       </div>
                       <button
                          type="submit"
                          disabled={!assistantGoal.trim() || isGeneratingPlan}
                          className="w-full bg-green-600 text-white py-3 rounded-xl font-bold hover:bg-green-700 transition-all flex justify-center items-center gap-2 shadow-md disabled:opacity-50 disabled:cursor-not-allowed"
                       >
                          {isGeneratingPlan ? (
                             <>
                                <Loader2 className="h-5 w-5 animate-spin" />
                                Analyse en cours...
                             </>
                          ) : (
                             <>
                                <Sparkles className="h-5 w-5" />
                                Générer mon plan
                             </>
                          )}
                       </button>
                    </form>
                 </div>

